Bubble.pseudoCode:
for i from 0 to N-1:
  for j from 0 to N-i-1:
    if a[j] > a[j+1]:
      swap(a[j], a[j+1])

Selection.pseudoCode:
for i from 0 to N-1:
  minIndex = i
  for j from i+1 to N:
    if a[j] < a[minIndex]:
      minIndex = j
  swap(a[i], a[minIndex])

Merge.pseudoCode:
function mergeSort(arr):
  if length of arr <= 1 return arr
  mid = length of arr / 2
  left = mergeSort(arr[0...mid])
  right = mergeSort(arr[mid...end])
  return merge(left, right)

Quick.pseudoCode:
function quickSort(arr, low, high):
  if low < high:
    pi = partition(arr, low, high)
    quickSort(arr, low, pi - 1)
    quickSort(arr, pi + 1, high)

Heap / Radix.pseudoCode:
function heapSort(arr):
  buildMaxHeap(arr)
  for i from length of arr down to 1:
    swap(arr[0], arr[i])
    heapify(arr, 0, i)

