dist[source] = 0
while Q is not empty:
  u = vertex in Q with min dist[u]
  remove u from Q
  for each neighbor v of u:
    alt = dist[u] + length(u, v)
    if alt < dist[v]:
      dist[v] = alt

0/1 Knapsack.pseudoCode:
for w from 0 to W:
  dp[0][w] = 0
for i from 1 to n:
  for w from 0 to W:
    if weight[i-1] <= w:
      dp[i][w] = max(val[i-1] + dp[i-1][w-weight[i-1]], dp[i-1][w])
    else:
      dp[i][w] = dp[i-1][w]
